def zeta_transform(F,n):
    # res[i] = (iを含む集合jに対する F[j] の和)
    N = 1 << n
    res = F[:]
    for i in range(n):
        k = 1 << i
        for j in range(N):
            if not j & k:
                res[j] += res[j^k]
    return res


