def binarySearch(arr, n, key):
    left = 0
    right = n - 1
    res = -1
    while (left <= right):
        mid = (right + left) // 2
        if (arr[mid] >= key):
            res = arr[mid]
            right = mid - 1
        else:
            left = mid + 1
    return res
def binarySearch1(arr, n, key):
    left = 0
    right = n - 1
    res = -1
    while (left <= right):
        mid = (right + left) // 2
        if (arr[mid]>=key):
            right = mid - 1
        else:
            res = arr[mid]
            left = mid + 1
    return res


